-- 🛠️ CREACIÓN DE ESTRUCTURAS (TABLAS)

CREATE TABLE "Usuarios" (
  "IdUsuario" SERIAL NOT NULL,
  "Nombre" CHARACTER VARYING(255) NOT NULL,
  "Correo" CHARACTER VARYING(100) NOT NULL,
  "Clave" CHARACTER VARYING(255) NOT NULL,
  "Estado" CHARACTER VARYING(20) DEFAULT 'pendiente',
  "IdRol" INTEGER,
  "TipoDocumento" CHARACTER VARYING(50),
  "NumeroDocumento" CHARACTER VARYING(20),
  "Telefono" CHARACTER VARYING(20),
  "MustChangePassword" BOOLEAN NOT NULL DEFAULT false,
  "ResetPasswordToken" CHARACTER VARYING(255),
  "ResetPasswordExpires" TIMESTAMP WITH TIME ZONE,
  "SessionId" CHARACTER VARYING(255),
  "LastActivity" TIMESTAMP WITH TIME ZONE,
  "SessionIdApp" CHARACTER VARYING(255),
  "LastActivityApp" TIMESTAMP WITH TIME ZONE,
  CONSTRAINT "Usuarios_pkey" PRIMARY KEY ("IdUsuario")
);

CREATE TABLE "Roles" (
  "IdRol" SERIAL NOT NULL,
  "Nombre" CHARACTER VARYING(50) NOT NULL,
  "Descripcion" TEXT,
  "Estado" BOOLEAN NOT NULL DEFAULT true,
  "Permisos" JSON,
  CONSTRAINT "Roles_pkey" PRIMARY KEY ("IdRol")
);

CREATE TABLE "Categorias" (
  "IdCategoria" SERIAL NOT NULL,
  "Nombre" CHARACTER VARYING(255) NOT NULL,
  "Descripcion" TEXT,
  "ImagenUrl" CHARACTER VARYING(500),
  "Estado" BOOLEAN NOT NULL DEFAULT true,
  CONSTRAINT "Categorias_pkey" PRIMARY KEY ("IdCategoria")
);

CREATE TABLE "Productos" (
  "IdProducto" SERIAL NOT NULL,
  "Nombre" CHARACTER VARYING(200) NOT NULL,
  "Categoria" CHARACTER VARYING(100),
  "IdCategoria" INTEGER NOT NULL,
  "Descripcion" TEXT,
  "PrecioCompra" DECIMAL(10,2),
  "PrecioVenta" DECIMAL(10,2) NOT NULL DEFAULT 0,
  "PrecioOferta" DECIMAL(10,2) DEFAULT 0,
  "PrecioMayorista6" DECIMAL(10,2) DEFAULT 0,
  "PrecioMayorista80" DECIMAL(10,2) DEFAULT 0,
  "EnOfertaVenta" BOOLEAN NOT NULL DEFAULT false,
  "PorcentajeDescuento" INTEGER,
  "EnInventario" BOOLEAN NOT NULL DEFAULT true,
  "Stock" INTEGER NOT NULL DEFAULT 0,
  "TallasStock" JSON,
  "Colores" JSON,
  "Imagenes" JSON,
  "Sales" INTEGER NOT NULL DEFAULT 0,
  "IsActive" BOOLEAN NOT NULL DEFAULT true,
  "DeletedAt" TIMESTAMP WITH TIME ZONE,
  CONSTRAINT "Productos_pkey" PRIMARY KEY ("IdProducto")
);

CREATE TABLE "Tallas" (
  "IdTalla" SERIAL,
  "Nombre" CHARACTER VARYING(50) NOT NULL,
  "Cantidad" INTEGER DEFAULT 0,
  "Estado" BOOLEAN DEFAULT true,
  CONSTRAINT "Tallas_pkey" PRIMARY KEY ("IdTalla")
);

CREATE TABLE "Proveedores" (
  "IdProveedor" SERIAL NOT NULL,
  "TipoProveedor" CHARACTER VARYING(50),
  "Nombre" CHARACTER VARYING(255) NOT NULL,
  "Contacto" CHARACTER VARYING(255),
  "TipoDocumento" CHARACTER VARYING(50) NOT NULL,
  "NumeroDocumento" CHARACTER VARYING(20) NOT NULL,
  "Telefono" CHARACTER VARYING(20),
  "Direccion" CHARACTER VARYING(200),
  "Email" CHARACTER VARYING(100) NOT NULL,
  "Ciudad" CHARACTER VARYING(100),
  "Estado" BOOLEAN NOT NULL DEFAULT true,
  CONSTRAINT "Proveedores_pkey" PRIMARY KEY ("IdProveedor")
);

CREATE TABLE "Clientes" (
  "IdCliente" SERIAL NOT NULL,
  "TipoDocumento" CHARACTER VARYING(50) NOT NULL,
  "Documento" CHARACTER VARYING(50) NOT NULL,
  "Nombre" CHARACTER VARYING(255) NOT NULL,
  "Telefono" CHARACTER VARYING(20),
  "Email" CHARACTER VARYING(100) NOT NULL,
  "Estado" BOOLEAN NOT NULL DEFAULT true,
  "Ciudad" CHARACTER VARYING(50),
  "Direccion" CHARACTER VARYING(200),
  "Avatar" TEXT,
  CONSTRAINT "Clientes_pkey" PRIMARY KEY ("IdCliente")
);

CREATE TABLE "Compras" (
  "IdCompra" SERIAL,
  "IdProveedor" INTEGER,
  "Nfactura" CHARACTER VARYING(100),
  "Fecha" TIMESTAMP WITH TIME ZONE NOT NULL,
  "Total" DECIMAL(10,2) NOT NULL DEFAULT 0,
  "MetodoPago" CHARACTER VARYING(50) NOT NULL DEFAULT 'Efectivo',
  "Estado" CHARACTER VARYING(50) NOT NULL DEFAULT 'Completada',
  "FechaRegistro" TIMESTAMP WITH TIME ZONE,
  CONSTRAINT "Compras_pkey" PRIMARY KEY ("IdCompra")
);

CREATE TABLE "CompraDetalles" (
  "IdDetalle" SERIAL,
  "IdCompra" INTEGER NOT NULL,
  "IdProducto" INTEGER,
  "Nfactura" CHARACTER VARYING(100),
  "NombreProducto" CHARACTER VARYING(255) NOT NULL,
  "Cantidad" INTEGER DEFAULT 1,
  "PrecioCompra" DECIMAL(10,2) NOT NULL DEFAULT 0,
  "PrecioVenta" DECIMAL(10,2) DEFAULT 0,
  "PrecioMayorista6" DECIMAL(10,2) DEFAULT 0,
  "PrecioMayorista80" DECIMAL(10,2) DEFAULT 0,
  "Subtotal" DECIMAL(10,2) DEFAULT 0,
  "Variantes" JSON,
  CONSTRAINT "CompraDetalles_pkey" PRIMARY KEY ("IdDetalle")
);

CREATE TABLE "Ventas" (
  "IdVenta" SERIAL NOT NULL,
  "IdCliente" INTEGER,
  "IdEstado" CHARACTER VARYING(50) NOT NULL DEFAULT 'Pendiente',
  "Fecha" TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "Total" DECIMAL(10,2) NOT NULL DEFAULT 0,
  "MetodoPago" CHARACTER VARYING(50),
  "DireccionEnvio" CHARACTER VARYING(255),
  "TipoEntrega" CHARACTER VARYING(50),
  "Comprobante" CHARACTER VARYING(500),
  "Comprobante2" CHARACTER VARYING(500),
  "MontoPagado" DECIMAL(10,2) DEFAULT 0,
  "Monto1" DECIMAL(10,2) DEFAULT 0,
  "Monto2" DECIMAL(10,2) DEFAULT 0,
  "MotivoRechazo" TEXT,
  "NoVenta" CHARACTER VARYING(100),
  "StatusEnvio" CHARACTER VARYING(50) DEFAULT 'Por enviar',
  "FechaEnvio" TIMESTAMP WITH TIME ZONE,
  "FechaEntrega" TIMESTAMP WITH TIME ZONE,
  "EsManual" BOOLEAN NOT NULL DEFAULT false,
  CONSTRAINT "Ventas_pkey" PRIMARY KEY ("IdVenta")
);

CREATE TABLE "DetalleVentas" (
  "IdDetalleVenta" SERIAL NOT NULL,
  "IdVenta" INTEGER NOT NULL,
  "IdProducto" INTEGER NOT NULL,
  "NombreProducto" CHARACTER VARYING(255),
  "Cantidad" INTEGER NOT NULL,
  "Talla" CHARACTER VARYING(20),
  "Precio" DECIMAL(10,2) NOT NULL,
  "Subtotal" DECIMAL(10,2) NOT NULL,
  "NoVenta" CHARACTER VARYING(100),
  CONSTRAINT "DetalleVentas_pkey" PRIMARY KEY ("IdDetalleVenta")
);

CREATE TABLE "Devoluciones" (
  "IdDevolucion" SERIAL NOT NULL,
  "IdProducto" INTEGER,
  "IdProductoCambio" INTEGER,
  "IdVenta" INTEGER,
  "IdEstado" CHARACTER VARYING(50) DEFAULT 'Pendiente',
  "Cantidad" INTEGER,
  "Valor" DECIMAL(10,2),
  "Fecha" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  "Estado" BOOLEAN DEFAULT true,
  "Motivo" TEXT,
  "Observacion" TEXT,
  "TipoDocumento" CHARACTER VARYING(20),
  "NumeroDocumento" CHARACTER VARYING(20),
  "ProductoOriginal" CHARACTER VARYING(255),
  "ProductoCambio" CHARACTER VARYING(255),
  "Evidencia" TEXT,
  "Evidencia2" TEXT,
  "NombreCliente" CHARACTER VARYING(255),
  "Talla" CHARACTER VARYING(20),
  "mismoModelo" BOOLEAN DEFAULT false,
  "pedidoCompleto" BOOLEAN DEFAULT false,
  "NoVenta" CHARACTER VARYING(100),
  "idLote" CHARACTER VARYING(100),
  "NoDevolucion" INTEGER,
  CONSTRAINT "Devoluciones_pkey" PRIMARY KEY ("IdDevolucion")
);

CREATE TABLE "Permisos" (
  "IdPermiso" CHARACTER VARYING(50) NOT NULL,
  "Nombre" TEXT NOT NULL,
  "Modulo" CHARACTER VARYING(50) NOT NULL,
  "Accion" CHARACTER VARYING(20) NOT NULL,
  CONSTRAINT "Permisos_pkey" PRIMARY KEY ("IdPermiso")
);

CREATE TABLE "DetallePermisos" (
  "IdDetalle" SERIAL NOT NULL,
  "IdRol" INTEGER NOT NULL,
  "IdPermiso" CHARACTER VARYING(50) NOT NULL,
  CONSTRAINT "DetallePermisos_pkey" PRIMARY KEY ("IdDetalle")
);

CREATE TABLE "Estado" (
  "IdEstado" SERIAL NOT NULL,
  "Nombre" CHARACTER VARYING(50) NOT NULL,
  "Estado" BOOLEAN NOT NULL DEFAULT true,
  CONSTRAINT "Estado_pkey" PRIMARY KEY ("IdEstado")
);

CREATE TABLE "Imagenes" (
  "IdImagen" SERIAL NOT NULL,
  "IdProducto" INTEGER NOT NULL,
  "Url" CHARACTER VARYING(255) NOT NULL,
  CONSTRAINT "Imagenes_pkey" PRIMARY KEY ("IdImagen")
);

CREATE TABLE "Colores" (
  "IdColor" SERIAL,
  "Nombre" CHARACTER VARYING(50) NOT NULL,
  "Hex" CHARACTER VARYING(10) NOT NULL,
  CONSTRAINT "Colores_pkey" PRIMARY KEY ("IdColor")
);

